// Parse the AI response and prepare for Airtable storage
const aiResponse = $input.first().json;
const content = aiResponse.content[0].text;

// Parse the JSON from Claude's response
let qualification;
try {
  // Handle case where Claude wraps JSON in markdown code blocks
  const jsonMatch = content.match(/```(?:json)?\s*([\s\S]*?)```/) || [null, content];
  qualification = JSON.parse(jsonMatch[1].trim());
} catch (e) {
  qualification = { error: 'Failed to parse AI response', raw: content };
}

return [{
  json: {
    url: $('Webhook: Qualify URL').first().json.url,
    qualification: qualification,
    lead_score: qualification.lead_score?.total || 0,
    recommendation: qualification.lead_score?.recommendation || 'unknown',
    retailer_name: qualification.retailer_name || 'Unknown',
    analysis_date: new Date().toISOString()
  }
}];
